import{toDependency}from"../../util/input.js";import{getPackageNameFromFilePath}from"../../util/modules.js";import{hasDependency}from"../../util/plugin.js";const title="Changesets",enablers=["@changesets/cli"],isEnabled=({dependencies:e})=>hasDependency(e,enablers),isRootOnly=!0,config=[".changeset/config.json"],resolveConfig=e=>{const n=(Array.isArray(e.changelog)?[e.changelog[0]]:"string"==typeof e.changelog?[e.changelog]:[]).map(e=>toDependency(e));if(e.$schema?.includes("node_modules/")){const o=getPackageNameFromFilePath(e.$schema);o&&n.push(toDependency(o))}return n},plugin={title:title,enablers:enablers,isEnabled:isEnabled,isRootOnly:true,config:config,resolveConfig:resolveConfig};export default plugin;